            if (copy_field_to_buffer(field_start, current_pos, max_field_size) != 0) {
                free(buffer);
                return -1;  // Field copy failed
            }

            // Move to next position in buffer
            current_pos += max_field_size;

            // Find next field in CSV record
            while (*field_start != '\0' && *field_start != ',') {
                field_start++;
            }

            // Skip comma if present
            if (*field_start == ',') {
                field_start++;
            }
        }
    }

    // Set output parameter
    *parsed_buffer = buffer;

    return 0;  // Success
}
